import{c as a,Q as i,j as e,m as t}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"rebase 深入","description":"","frontmatter":{},"headers":[],"relativePath":"gitLearning/08-rebase深入.md","filePath":"gitLearning/08-rebase深入.md","lastUpdated":1778496697000}'),n={name:"gitLearning/08-rebase深入.md"};function p(l,s,o,h,r,c){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="rebase-深入" tabindex="-1">rebase 深入 <a class="header-anchor" href="#rebase-深入" aria-label="Permalink to &quot;rebase 深入&quot;">​</a></h1><p>rebase 是 git 里最强大也最被误解的命令。误解的来源就一句话——&quot;rebase 会改历史&quot;。听上去吓人,但<strong>理解之后你会发现</strong>:rebase 不会&quot;丢&quot;任何东西(reflog 全留着),它只是把一段 commit <strong>复制一份重新接到另一个位置</strong>。学会 rebase 之后,你的 PR 历史会从&quot;丑陋的 merge 合集&quot;变成<strong>线性的、能讲故事的、能 review 的提交链</strong>。</p><blockquote><p>一句话先记住:<strong>rebase 是&quot;把这一串 commit 在另一个 base 上重新做一遍&quot;</strong>。本质是一系列 cherry-pick——拿你 commit 的 diff、在新 base 上重新生成新 commit。新 commit 哈希都不一样了,所以叫&quot;改历史&quot;。<strong>改的是哈希,不是改成另一个内容</strong>。</p></blockquote><hr><h2 id="一、rebase-到底在干嘛" tabindex="-1">一、rebase 到底在干嘛 <a class="header-anchor" href="#一、rebase-到底在干嘛" aria-label="Permalink to &quot;一、rebase 到底在干嘛&quot;">​</a></h2><p>来看场景:你在 feature 分支上做了 D / E 两个 commit;期间 main 也加了 F:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F          ← main</span></span>
<span class="line"><span>        ↘</span></span>
<span class="line"><span>         D → E         ← feature(HEAD)</span></span></code></pre></div><p>你想&quot;把 feature 接到 main 最新位置&quot;。两条路:</p><p><strong>A. merge</strong>(07 篇讲过):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p>结果:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F ───→ M    ← feature</span></span>
<span class="line"><span>        ↘         ↗</span></span>
<span class="line"><span>         D → E ──┘</span></span></code></pre></div><p>新建一个 merge commit M,<strong>保留分叉</strong>。</p><p><strong>B. rebase</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p>结果:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F → D&#39; → E&#39;    ← feature</span></span></code></pre></div><p><strong>没有分叉,完全线性</strong>。D / E 被复制成 D&#39; / E&#39;(新 hash),原来的 D / E 还在 reflog 里(没指针指,90 天后被 GC)。</p><blockquote><p>rebase 的视觉效果像&quot;把 feature 这条侧支拔起来,重新插到 F 后面&quot;。<strong>改的不是 commit 内容,是它在图上的位置</strong>。</p></blockquote><hr><h2 id="二、最简-rebase-流程" tabindex="-1">二、最简 rebase 流程 <a class="header-anchor" href="#二、最简-rebase-流程" aria-label="Permalink to &quot;二、最简 rebase 流程&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 切到要&quot;被移动&quot;的分支</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 把当前分支 rebase 到 main 上</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p>如果没冲突:<strong>几秒搞定</strong>,你看到 &quot;Successfully rebased and updated&quot;。</p><p>如果有冲突:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFLICT (content): Merge conflict in src/a.ts</span></span>
<span class="line"><span>error: could not apply abc1234... your commit message</span></span>
<span class="line"><span>hint: Resolve all conflicts manually, mark them as resolved with</span></span>
<span class="line"><span>hint: &quot;git add &lt;conflicted_files&gt;&quot;, then run &quot;git rebase --continue&quot;.</span></span></code></pre></div><p>解冲突的步骤(和 merge 类似,但<strong>重要差别</strong>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 编辑冲突文件,删 marker</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. add(注意!不要 commit)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/a.ts</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 继续 rebase,git 自动接着应用下一个 commit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span></span></code></pre></div><p><code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</code> 这边是<strong>已经 rebase 过去的&quot;新 base 上的内容&quot;</strong>(不是你原来的 commit);<code>&gt;&gt;&gt;&gt;&gt;&gt;&gt; abc1234</code> 才是<strong>你正在 rebase 的那个 commit</strong>。这跟 merge 时正反两边正好相反——别看错了。</p><p>中途想撤销:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abort</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 完全回到 rebase 之前的状态</span></span></code></pre></div><p>跳过某个 commit(罕见用):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skip</span></span></code></pre></div><hr><h2 id="三、interactive-rebase-改老-commit-的瑞士军刀" tabindex="-1">三、interactive rebase:改老 commit 的瑞士军刀 <a class="header-anchor" href="#三、interactive-rebase-改老-commit-的瑞士军刀" aria-label="Permalink to &quot;三、interactive rebase:改老 commit 的瑞士军刀&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~5</span></span></code></pre></div><p>意思是&quot;对最近 5 个 commit 做交互式 rebase&quot;。git 弹出编辑器:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pick  a3f5b2c first commit</span></span>
<span class="line"><span>pick  d8e9f0a second commit</span></span>
<span class="line"><span>pick  4f5a6b7 typo</span></span>
<span class="line"><span>pick  8c9d0e1 fix typo of typo</span></span>
<span class="line"><span>pick  e1f2a3b another commit</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Commands:</span></span>
<span class="line"><span># p, pick   = use commit</span></span>
<span class="line"><span># r, reword = use commit, but edit the message</span></span>
<span class="line"><span># e, edit   = use commit, but stop for amending</span></span>
<span class="line"><span># s, squash = use commit, but meld into previous (combines messages)</span></span>
<span class="line"><span># f, fixup  = like &quot;squash&quot;, but discard this commit&#39;s log message</span></span>
<span class="line"><span># d, drop   = remove commit</span></span></code></pre></div><p>把 <code>pick</code> 改成不同动作就实现不同操作:</p><table tabindex="0"><thead><tr><th>动作</th><th>干啥</th></tr></thead><tbody><tr><td><code>pick</code></td><td>保留</td></tr><tr><td><code>reword</code></td><td>保留但改 message</td></tr><tr><td><code>edit</code></td><td>暂停在这个 commit,让你改内容(amend)</td></tr><tr><td><code>squash</code></td><td>合进上一个 commit,<strong>保留两边 message</strong></td></tr><tr><td><code>fixup</code></td><td>合进上一个 commit,<strong>丢弃自己 message</strong></td></tr><tr><td><code>drop</code></td><td>删掉这个 commit</td></tr><tr><td>调整顺序</td><td>直接拖动行,改顺序就改了</td></tr></tbody></table><p>把上面 5 个 commit 整理成 2 个:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pick  a3f5b2c first commit</span></span>
<span class="line"><span>pick  d8e9f0a second commit</span></span>
<span class="line"><span>fixup 4f5a6b7 typo                  ← 合进 second</span></span>
<span class="line"><span>fixup 8c9d0e1 fix typo of typo      ← 合进 second</span></span>
<span class="line"><span>pick  e1f2a3b another commit</span></span></code></pre></div><p>保存退出后 git 自动按你的指令重写。<strong>最后只剩 3 个 commit,历史干净</strong>。</p><blockquote><p>interactive rebase 是<strong>整理 PR 历史的核心工具</strong>——本地写代码时随便 commit <code>wip / fix / typo</code>,push 之前用 <code>rebase -i</code> 整理成 3-5 个有逻辑边界的 commit。</p></blockquote><hr><h2 id="四、-onto-三角-rebase" tabindex="-1">四、<code>--onto</code>:三角 rebase <a class="header-anchor" href="#四、-onto-三角-rebase" aria-label="Permalink to &quot;四、\`--onto\`:三角 rebase&quot;">​</a></h2><p>最强大也最少人会用的形式。场景:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C            ← main</span></span>
<span class="line"><span>    ↘</span></span>
<span class="line"><span>     D → E           ← old-feature</span></span>
<span class="line"><span>         ↘</span></span>
<span class="line"><span>          F → G      ← new-feature</span></span></code></pre></div><p>你在 <code>new-feature</code> 上做了 F / G,但它现在挂在 <code>old-feature</code> 上(后者已废弃)。你想把 F / G <strong>直接接到 main</strong>——不带 D / E。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --onto</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> old-feature</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new-feature</span></span></code></pre></div><p>参数读法:<strong>把 <code>new-feature</code> 这条分支,从 <code>old-feature</code> 这个点之后,搬到 <code>main</code> 上</strong>。</p><p>结果:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F&#39; → G&#39;   ← new-feature</span></span>
<span class="line"><span>    ↘</span></span>
<span class="line"><span>     D → E             ← old-feature(没动)</span></span></code></pre></div><blockquote><p><code>--onto</code> 是 git 里&quot;小命令大威力&quot;的代表。掌握之后,<strong>分支移植 / 切片 / 拆 PR 都用一条命令</strong>。</p></blockquote><hr><h2 id="五、rebase-的-golden-rule" tabindex="-1">五、rebase 的 golden rule <a class="header-anchor" href="#五、rebase-的-golden-rule" aria-label="Permalink to &quot;五、rebase 的 golden rule&quot;">​</a></h2><p><strong>永远不要 rebase 已经 push 出去的 commit</strong>——除非你 100% 确定没人在用那段历史。</p><p>为什么:rebase 改了 commit 哈希,push 上去就<strong>强行改写了远程历史</strong>。别人本地是旧哈希,下次 pull 会:</p><ul><li>要么 git 报错拒绝合并</li><li>要么 git 把旧 commit 当成&quot;新 commit&quot;再合一遍,<strong>生成奇形怪状的拓扑</strong></li></ul><p><strong>安全的 rebase 范围</strong>:</p><ul><li>完全本地、还没 push 的 commit(随便 rebase)</li><li>你私人的 feature 分支,只有你一个人用(可以 rebase + force push)</li></ul><p><strong>不要 rebase 的地方</strong>:</p><ul><li>main / develop 等公共分支</li><li>别人也在 push 的共享分支</li></ul><blockquote><p>不破规则的话 rebase 跟 merge 一样安全。一破规则<strong>事故等级直接拉到&quot;全队工作流被搅乱&quot;</strong>。这条规则是 git 协作的硬底线,所有团队都遵守。</p></blockquote><hr><h2 id="六、push-force-with-lease-rebase-后的安全推法" tabindex="-1">六、<code>push --force-with-lease</code>:rebase 后的安全推法 <a class="header-anchor" href="#六、push-force-with-lease-rebase-后的安全推法" aria-label="Permalink to &quot;六、\`push --force-with-lease\`:rebase 后的安全推法&quot;">​</a></h2><p>rebase 完私人分支需要 force push(否则 git 拒绝,因为远端 hash 不一样)。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # ❌ 危险:无脑覆盖远端</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force-with-lease</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # ✅ 安全:只在远端&quot;还是我上次 fetch 时看到的状态&quot;才覆盖</span></span></code></pre></div><p><code>--force-with-lease</code> 的判断:</p><ul><li><strong>远端 hash 和我本地认为的远端 hash 一样</strong> → 推</li><li><strong>远端被别人推过新 commit 了</strong>(我没 fetch 过) → 拒绝,提示&quot;远端变了&quot;</li></ul><p>防止&quot;我 rebase 时队友刚 push 了一个新 commit,我 force 覆盖了他&quot;。</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[alias]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    please</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = push --force-with-lease</span></span></code></pre></div><p><strong>所有 force push 都用 <code>git please</code></strong>——避免无脑 <code>--force</code> 灭顶之灾。</p><hr><h2 id="七、pull-rebase" tabindex="-1">七、<code>pull --rebase</code> <a class="header-anchor" href="#七、pull-rebase" aria-label="Permalink to &quot;七、\`pull --rebase\`&quot;">​</a></h2><p><code>git pull</code> 默认是 <code>fetch + merge</code>。这意味着每次 pull 远程有新东西、本地有未 push commit 时,产生一个 merge commit:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F        ← origin/main</span></span>
<span class="line"><span>        ↘     ↘</span></span>
<span class="line"><span>         D → E → M   ← main(本地)</span></span></code></pre></div><p>M 这个 merge commit 是<strong>纯噪声</strong>——你只是想拉最新内容,不是想表达&quot;分支合并&quot;。</p><p>设 <code>pull.rebase=true</code>(02 篇讲过):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull.rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre></div><p>之后 <code>git pull</code> 等于 <code>fetch + rebase</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F → D&#39; → E&#39;    ← main</span></span></code></pre></div><p><strong>线性、干净、零 merge commit 噪声</strong>。</p><blockquote><p>这个设置一改,git 历史质量立刻提升一档。<strong>反对它的唯一理由是&quot;我习惯看到 merge commit&quot;</strong>——但绝大多数团队都同意线性历史好看。</p></blockquote><hr><h2 id="八、autosquash-更快地整理" tabindex="-1">八、<code>autosquash</code>:更快地整理 <a class="header-anchor" href="#八、autosquash-更快地整理" aria-label="Permalink to &quot;八、\`autosquash\`:更快地整理&quot;">​</a></h2><p>写代码时发现某个 commit 有 typo,你想&quot;修复后合进那个原 commit&quot;:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 改完代码之后:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --fixup=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">那个原</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> has</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --squash=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">那个原</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> has</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>git 自动生成 <code>fixup! 原 message</code> 形式的 commit。然后 rebase 时:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --autosquash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~10</span></span></code></pre></div><p>git 自动把 <code>fixup!</code> commit 排到对应原 commit 下方并标 fixup,<strong>省去你手工拖动</strong>。</p><p>设默认:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[rebase]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    autosquash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = true</span></span></code></pre></div><p>之后 <code>rebase -i</code> 总会自动 autosquash。</p><hr><h2 id="九、rebase-vs-merge-什么时候用哪个" tabindex="-1">九、rebase vs merge:什么时候用哪个 <a class="header-anchor" href="#九、rebase-vs-merge-什么时候用哪个" aria-label="Permalink to &quot;九、rebase vs merge:什么时候用哪个&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐</th></tr></thead><tbody><tr><td>个人 feature 分支,要合进 main</td><td><strong>rebase + squash 或 rebase + 几个原子 commit</strong></td></tr><tr><td>公共分支拉最新进度</td><td><code>pull --rebase</code></td></tr><tr><td>长期 feature 分支(几周),期间多人协作</td><td>merge,因为多人就不能 rebase 了</td></tr><tr><td>把一个 PR revert</td><td>merge(留 merge commit 好 revert 整 PR)</td></tr><tr><td>想保留&quot;这个 feature 是独立做的&quot;信息</td><td>merge <code>--no-ff</code></td></tr><tr><td>想要超干净的线性历史</td><td>rebase + squash merge</td></tr></tbody></table><p><strong>典型团队工作流</strong>:</p><ol><li>feature 分支上随意 commit</li><li>PR 之前 <code>git rebase -i HEAD~N</code> 整理成几个有逻辑的 commit</li><li>PR review 期间 main 有更新 → <code>git rebase main</code>(force-with-lease)</li><li>合 PR 时 squash 或 merge,看团队规范</li></ol><hr><h2 id="十、interactive-rebase-的几个进阶招" tabindex="-1">十、interactive rebase 的几个进阶招 <a class="header-anchor" href="#十、interactive-rebase-的几个进阶招" aria-label="Permalink to &quot;十、interactive rebase 的几个进阶招&quot;">​</a></h2><h3 id="_10-1-exec-在-rebase-中跑命令" tabindex="-1">10.1 <code>exec</code>:在 rebase 中跑命令 <a class="header-anchor" href="#_10-1-exec-在-rebase-中跑命令" aria-label="Permalink to &quot;10.1 \`exec\`:在 rebase 中跑命令&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pick  a3f5b2c commit 1</span></span>
<span class="line"><span>exec  npm test                     # 跑测试,失败就停下让你修</span></span>
<span class="line"><span>pick  d8e9f0a commit 2</span></span>
<span class="line"><span>exec  npm test</span></span></code></pre></div><p>或一行命令:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;npm test&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~5</span></span></code></pre></div><p><strong>每个 commit 之后跑一次测试,确保中间任何 commit 都能编译 / 通过测试</strong>——这是&quot;原子 commit + bisect 友好&quot;的硬保障。</p><h3 id="_10-2-break-在某个-commit-暂停" tabindex="-1">10.2 <code>break</code>:在某个 commit 暂停 <a class="header-anchor" href="#_10-2-break-在某个-commit-暂停" aria-label="Permalink to &quot;10.2 \`break\`:在某个 commit 暂停&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pick  a3f5b2c commit 1</span></span>
<span class="line"><span>break                             ← 这里停下,让我手工干点事</span></span>
<span class="line"><span>pick  d8e9f0a commit 2</span></span></code></pre></div><p>跑到 break 时 git 暂停,你随便操作完 <code>git rebase --continue</code>。</p><h3 id="_10-3-改老-commit-的作者-时间" tabindex="-1">10.3 改老 commit 的作者 / 时间 <a class="header-anchor" href="#_10-3-改老-commit-的作者-时间" aria-label="Permalink to &quot;10.3 改老 commit 的作者 / 时间&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD~5</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 把要改的标 edit</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 到那个 commit 时:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --amend</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --author=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;新名字 &lt;新邮箱&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --date=now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rebase</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span></span></code></pre></div><hr><h2 id="十一、踩坑提醒" tabindex="-1">十一、踩坑提醒 <a class="header-anchor" href="#十一、踩坑提醒" aria-label="Permalink to &quot;十一、踩坑提醒&quot;">​</a></h2><ol><li><strong>rebase 公共分支</strong>——破了 golden rule,搅乱全队</li><li><strong><code>push --force</code> 一把梭</strong>——队友未 fetch 的 commit 被覆盖,改用 <code>--force-with-lease</code></li><li><strong>rebase 中途冲突,误用 <code>git commit</code> 而不是 <code>git rebase --continue</code></strong>——产生孤立 commit,搞乱进度</li><li><strong>冲突 marker <code>HEAD</code> / 名字读反</strong>——rebase 时 HEAD 是新 base 那边,不是你原来分支</li><li><strong>interactive rebase 改了一行没保存退出</strong>——以为没事,实际上 git 接收的是空脚本,会报错或全 drop</li><li><strong>rebase 一长段反复出现同一冲突</strong>——开 <code>rerere</code> 一次解了之后自动应用</li><li><strong>rebase 完忘了 push --force-with-lease</strong>——下次 push 报错&quot;远程比本地新&quot;,误以为别人加了什么</li><li><strong>rebase merge commit</strong>——默认会展平 merge commit 里的 commit,通常不是你想要的;用 <code>--rebase-merges</code> 保留 merge 拓扑</li></ol><hr><p>下一篇:<code>09-远程仓库与push-pull-fetch.md</code>,讲 remote 是什么、<code>fetch</code> / <code>pull</code> / <code>push</code> 的精确差别、为什么 fetch 比 pull 安全、tracking branch 和 upstream 的关系。</p>`,115)])])}const k=a(n,[["render",p]]);export{g as __pageData,k as default};
